import{_ as t,c as a,o as e,V as S}from"./chunks/framework.1sOznGPE.js";const _=JSON.parse('{"title":"CSR、SSR、SEO","description":"","frontmatter":{},"headers":[],"relativePath":"guide/node/CSR_SSR_SEO.md","filePath":"guide/node/CSR_SSR_SEO.md","lastUpdated":null}'),r={name:"guide/node/CSR_SSR_SEO.md"},d=S('<h1 id="csr、ssr、seo" tabindex="-1">CSR、SSR、SEO <a class="header-anchor" href="#csr、ssr、seo" aria-label="Permalink to &quot;CSR、SSR、SEO&quot;">​</a></h1><blockquote><p>CSR、SSR是渲染方式</p></blockquote><h2 id="csr" tabindex="-1">CSR <a class="header-anchor" href="#csr" aria-label="Permalink to &quot;CSR&quot;">​</a></h2><p>CSR（Client-Side Rendering）客户端渲染，指在客户端完成渲染拼接。</p><p>常见框架：Vue、React</p><h2 id="ssr" tabindex="-1">SSR <a class="header-anchor" href="#ssr" aria-label="Permalink to &quot;SSR&quot;">​</a></h2><p>SSR（Server-Side Rendering）服务端渲染，指请求数据和拼装都在服务端完成。</p><p>常见框架：Nuxt.js、Next.js</p><h2 id="csr和ssr区别" tabindex="-1">CSR和SSR区别 <a class="header-anchor" href="#csr和ssr区别" aria-label="Permalink to &quot;CSR和SSR区别&quot;">​</a></h2><table><thead><tr><th></th><th>CSR</th><th>SSR</th></tr></thead><tbody><tr><td>页面加载方式</td><td>在 CSR 中，服务器返回一个初始的 HTML 页面，然后浏览器下载并执行 JavaScript 文件，JavaScript 负责动态生成并更新页面内容。这意味着初始页面加载时，内容较少，页面结构和样式可能存在一定的延迟。</td><td>在 SSR 中，服务器在返回给浏览器之前，会预先在服务器端生成完整的 HTML 页面，包含了初始的页面内容。浏览器接收到的是已经渲染好的 HTML 页面，因此初始加载的速度较快。</td></tr><tr><td>内容生成和渲染</td><td>在 CSR 中，页面的内容生成和渲染是由客户端的 JavaScript 脚本负责的。当数据变化时，JavaScript 会重新生成并更新 DOM，从而实现内容的动态变化。这种方式使得前端开发更加灵活，可以创建复杂的交互和动画效果。</td><td>在 SSR 中，服务器在渲染页面时会执行应用程序的代码，并生成最终的 HTML 页面。这意味着页面的初始内容是由服务器生成的，对于一些静态或少变的内容，可以提供更好的首次加载性能。</td></tr><tr><td>用户交互和体验</td><td>在 CSR 中，一旦初始页面加载完成，后续的用户交互通常是通过 AJAX 或 WebSocket 与服务器进行数据交互，然后通过 JavaScript 更新页面内容。这种方式可以提供更快的页面切换和响应速度，但对于搜索引擎爬虫和 SEO（搜索引擎优化）来说，可能需要一些额外的处理。</td><td>在 SSR 中，由于页面的初始内容是由服务器生成的，因此用户交互可以直接在服务器上执行，然后服务器返回更新后的页面。这样可以提供更好的首次加载性能和对搜索引擎友好的内容。</td></tr></tbody></table><h3 id="哪些网站适合做csr-哪些适合做ssr呢" tabindex="-1">哪些网站适合做CSR 哪些适合做SSR呢？ <a class="header-anchor" href="#哪些网站适合做csr-哪些适合做ssr呢" aria-label="Permalink to &quot;哪些网站适合做CSR 哪些适合做SSR呢？&quot;">​</a></h3><p>CSR：例如 ToB 后台管理系统、大屏可视化、都可以采用CSR渲染不需要很高的SEO支持</p><p>SSR：例如 内容密集型应用大部分是ToC、新闻网站、博客网站、电子商务、门户网站等需要更高的SEO支持</p><h2 id="seo" tabindex="-1">SEO <a class="header-anchor" href="#seo" aria-label="Permalink to &quot;SEO&quot;">​</a></h2><p>SEO（Search Engine Optimization，搜索引擎优化）</p><ul><li><p>CSR应用：对SEO并不是很友好，因为在首次加载的时候获取HTML 信息较少 搜索引擎爬虫可能无法获取完整的页面内容</p></li><li><p>SSR应用：由于 SSR 在服务器端预先生成完整的 HTML 页面，搜索引擎爬虫可以直接获取到完整的页面内容。这有助于搜索引擎正确理解和评估页面的内容</p></li></ul>',16),s=[d];function o(i,c,n,R,l,h){return e(),a("div",null,s)}const u=t(r,[["render",o]]);export{_ as __pageData,u as default};
